const body=document.querySelector("body");const bodyBefore=document.createElement("div");bodyBefore.classList.add("background");body.insertBefore(bodyBefore,body.firstChild);document.addEventListener("mousemove",e=>{const sensitivity=31;const mouseX=(e.clientX/window.innerWidth-.5)*sensitivity;const mouseY=(e.clientY/window.innerHeight-.5)*sensitivity;bodyBefore.style.backgroundImage=`url('https://cdn.akamai.steamstatic.com/steamcommunity/public/images/items/1465680/ee46cc3b6988057d435be7e391472d46f278d87a.jpg')`;bodyBefore.style.backgroundSize="cover";bodyBefore.style.width="100vw";bodyBefore.style.height="100vh";bodyBefore.style.position="fixed";bodyBefore.style.top="0";bodyBefore.style.left="0";bodyBefore.style.zIndex="-1";bodyBefore.style.transformOrigin="center center";bodyBefore.style.transform=`scale(1.05) translate(${mouseX}px, ${mouseY}px)`});document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".profile-box, .social-box, .rounded-icon").forEach(function(element){element.classList.add("fadeIn")})});function updateTime(){const clockElement=document.querySelector(".animated-clock");const now=new Date;const hours=now.getHours().toString().padStart(2,"0");const minutes=now.getMinutes().toString().padStart(2,"0");const seconds=now.getSeconds().toString().padStart(2,"0");clockElement.textContent=`${hours}:${minutes}:${seconds}`}setInterval(updateTime,1e3);updateTime();
